+    }
+
+    // ==========================================================================
+    // Push span on empty text
+    // ==========================================================================
+
+    #[test]
+    fn push_span_on_empty_creates_line() {
+        let mut text = Text::new();
+        text.push_span(Span::raw("hello"));
+        assert_eq!(text.height(), 1);
+        assert_eq!(text.to_plain_text(), "hello");
+    }
