+    // From iterator tests
+    // ==========================================================================
+
+    #[test]
+    fn text_ref_into_iter() {
+        let text = Text::from_lines([Line::raw("a"), Line::raw("b")]);
+        let mut count = 0;
+        for _line in &text {
+            count += 1;
+        }
+        assert_eq!(count, 2);
+    }
